def shortest_path(topology, start, end):
    """
    Find shortest path between two qubits using BFS.

    Args:
        topology: Topology object with neighbors() method
        start: Starting qubit
        end: Target qubit
    Returns:
        List of qubits forming the path, or [] if no path
    """
    if start == end:
        return [start]

    # BFS with path tracking
    visited = {start}
    queue = [(start, [start])]

    while queue:
        current, path = queue.pop(0)

        for neighbor in topology.neighbors(current):
            if neighbor == end:
                return path + [end]

            if neighbor not in visited:
                visited.add(neighbor)
                queue.append((neighbor, path + [neighbor]))

    return []  # No path found

