class Topology:
    def __init__(self, edges):
        self.edges = set(edges)
    def neighbors(self, q):
        return [q2 if q1==q else q1 for q1,q2 in self.edges if q in (q1,q2)]

topo = Topology([(0, 1), (1, 2), (2, 3)])
print(shortest_path(topo, 0, 3))  # [0, 1, 2, 3]

from collections import defaultdict

class CircuitDAG:
    def __init__(self, gates, num_qubits):
        """
        Build DAG from gate list.

        Args:
            gates: List of (name, qubits) where qubits is tuple
            num_qubits: Total number of qubits
        """
        self.gates = gates
        self.num_qubits = num_qubits
        self.predecessors = defaultdict(list)
        self._build_dag()

    def _build_dag(self):
        """Build dependency edges."""
        # Track last gate on each qubit
        last_on_qubit = {}

        for i, (name, qubits) in enumerate(self.gates):
            for qubit in qubits:
                if qubit in last_on_qubit:
                    pred = last_on_qubit[qubit]
                    if pred not in self.predecessors[i]:
                        self.predecessors[i].append(pred)
                last_on_qubit[qubit] = i

    def depth(self):
        """
        Compute circuit depth (longest path).
        """
        depths = {}

        def compute_depth(node):
            if node in depths:
                return depths[node]

            preds = self.predecessors[node]
            if not preds:
                depths[node] = 1
            else:
                depths[node] = 1 + max(compute_depth(p) for p in preds)

            return depths[node]

        if not self.gates:
            return 0

        return max(compute_depth(i) for i in range(len(self.gates)))

# Test
gates = [
    ('H', (0,)),
    ('H', (1,)),
    ('CX', (0, 1)),
    ('H', (0,)),
]
dag = CircuitDAG(gates, 2)
print(dag.depth())  # 3: H(0)->CX->H(0), H(1) is parallel
